patch:
diff --git a/llvm/include/llvm/IR/Instructions.h b/llvm/include/llvm/IR/Instructions.h
index 95a0a7fd2f97..9bdef834ad1e 100644
--- a/llvm/include/llvm/IR/Instructions.h
+++ b/llvm/include/llvm/IR/Instructions.h
@@ -1491,7 +1491,10 @@ public:
   /// Return result of `LHS Pred RHS` comparison.
   LLVM_ABI static bool compare(const APFloat &LHS, const APFloat &RHS,
                                FCmpInst::Predicate Pred);
-
+  /// Determine if Pred1 implies Pred2 is true, false, or if nothing can be
+  /// inferred about the implication, when two compares have matching operands.
+  LLVM_ABI static std::optional<bool>
+  isImpliedByMatchingCmp(CmpPredicate Pred1, CmpPredicate Pred2);
   /// Methods for support type inquiry through isa, cast, and dyn_cast:
   static bool classof(const Instruction *I) {
     return I->getOpcode() == Instruction::FCmp;
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..fe5818fad597 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,30 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  if (LHS0 == RHS0 && LHS1 == RHS1) {
+    if (FCmpInst::isImpliedByMatchingCmp(PredL, PredR) == true)
+      return IsAnd ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+    if (FCmpInst::isImpliedByMatchingCmp(PredR, PredL) == true)
+      return IsAnd ? static_cast<Value *>(RHS) : static_cast<Value *>(LHS);
+    if (FCmpInst::isImpliedByMatchingCmp(PredL, PredR) == false)
+      return IsAnd ? ConstantInt::getFalse(LHS->getType())
+                   : static_cast<Value *>(nullptr); // P|Q is not generally simplified here.
+  }
+
+  // Handle fcmp with different constants.
+  if (LHS0 == RHS0) {
+    const APFloat *C0, *C1;
+    if (match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
+      // (fcmp nsz olt X, C0) | (fcmp nsz olt X, C1) -> fcmp nsz olt X, max(C0, C1)
+      if (!IsAnd && PredL == PredR && PredL == FCmpInst::FCMP_OLT) {
+        if (C0->compare(*C1) == APFloat::cmpLessThan)
+          return RHS;
+        else
+          return LHS;
+      }
+    }
+  }
+
   return nullptr;
 }

diff --git a/llvm/lib/IR/Instructions.cpp b/llvm/lib/IR/Instructions.cpp
index a1751c0ee3e4..aa31f9dfb3f7 100644
--- a/llvm/lib/IR/Instructions.cpp
+++ b/llvm/lib/IR/Instructions.cpp
@@ -4006,6 +4006,15 @@ std::optional<bool> ICmpInst::isImpliedByMatchingCmp(CmpPredicate Pred1,
   return std::nullopt;
 }

+std::optional<bool> FCmpInst::isImpliedByMatchingCmp(CmpPredicate Pred1,
+                                                     CmpPredicate Pred2) {
+  if (isImpliedTrueByMatchingCmp(Pred1, Pred2))
+    return true;
+  if (isImpliedFalseByMatchingCmp(Pred1, Pred2))
+    return false;
+  return std::nullopt;
+}
+
 //===----------------------------------------------------------------------===//
 //                       CmpPredicate Implementation
 //===----------------------------------------------------------------------===//

